const input = $input.first().json;
const outputText = input.output || '';
let jsonResult = null;

const jsonMatch = outputText.match(/```json\s*([\s\S]*?)\s*```/);
if (jsonMatch) {
    try {
        jsonResult = JSON.parse(jsonMatch[1].trim());
    } catch (e) {}
}

if (!jsonResult) {
    const objectMatch = outputText.match(/\{[\s\S]*\}/);
    if (objectMatch) {
        try {
            jsonResult = JSON.parse(objectMatch[0]);
        } catch (e) {}
    }
}

if (!jsonResult) {
    return [{ json: { output: { error: 'No se pudo extraer JSON válido', raw_output: outputText } } }];
}

return [{ json: { output: {
    status: jsonResult.status || 'unknown',
    file_name: jsonResult.file_name || '',
    content: jsonResult.content || '',
    changes: jsonResult.changes || '',
    verification_notes: jsonResult.verification_notes || '',
    remaining_errors: jsonResult.remaining_errors || []
}}}];

const input = $input.first().json;
const body = input.body || input;

const folderPath = body.folder_path || '';
const configFiles = body.files || [];

const items = configFiles.map(filename => ({
    json: {
        config_file: filename,
        folder_path: folderPath
    }
}));

return items;

